import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"北京旅游实用指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":null}'),i={name:"guide/index.md"};function r(n,t,s,g,h,o){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="北京旅游实用指南" tabindex="-1">北京旅游实用指南 <a class="header-anchor" href="#北京旅游实用指南" aria-label="Permalink to &quot;北京旅游实用指南&quot;">​</a></h1><blockquote><p>&quot;行前准备充分，旅途更加顺心。&quot;</p></blockquote><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><ul><li><a href="/beijing-travel-guide/guide/best-time.html">最佳旅行时间</a></li><li><a href="/beijing-travel-guide/guide/transportation.html">交通指南</a></li><li><a href="/beijing-travel-guide/guide/tickets.html">门票预约</a></li><li><a href="/beijing-travel-guide/guide/routes.html">推荐路线</a></li><li><a href="/beijing-travel-guide/guide/food.html">美食推荐</a></li><li><a href="/beijing-travel-guide/guide/accommodation.html">住宿建议</a></li><li><a href="/beijing-travel-guide/guide/tips.html">注意事项</a></li></ul><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><h3 id="按类别浏览景点" tabindex="-1">按类别浏览景点 <a class="header-anchor" href="#按类别浏览景点" aria-label="Permalink to &quot;按类别浏览景点&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:left;">代表景点</th><th style="text-align:left;">链接</th></tr></thead><tbody><tr><td style="text-align:left;">🏛️ 名胜古迹</td><td style="text-align:left;">故宫、天坛、长城、颐和园</td><td style="text-align:left;"><a href="/beijing-travel-guide/landmarks/">/landmarks/</a></td></tr><tr><td style="text-align:left;">📜 近代历史</td><td style="text-align:left;">圆明园、天安门广场、北大红楼</td><td style="text-align:left;"><a href="/beijing-travel-guide/history/">/history/</a></td></tr><tr><td style="text-align:left;">⛪ 宗教建筑</td><td style="text-align:left;">四大天主教堂、雍和宫、白云观</td><td style="text-align:left;"><a href="/beijing-travel-guide/religion/">/religion/</a></td></tr><tr><td style="text-align:left;">🏛️ 博物馆</td><td style="text-align:left;">国博、首博、科技馆</td><td style="text-align:left;"><a href="/beijing-travel-guide/museums/">/museums/</a></td></tr><tr><td style="text-align:left;">🌳 城市公园</td><td style="text-align:left;">北海、景山、奥林匹克森林公园</td><td style="text-align:left;"><a href="/beijing-travel-guide/parks/">/parks/</a></td></tr></tbody></table><h3 id="按天数规划" tabindex="-1">按天数规划 <a class="header-anchor" href="#按天数规划" aria-label="Permalink to &quot;按天数规划&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">天数</th><th style="text-align:left;">推荐行程</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>1日游</strong></td><td style="text-align:left;">天安门广场 → 故宫 → 景山</td></tr><tr><td style="text-align:left;"><strong>2日游</strong></td><td style="text-align:left;">Day1: 天安门+故宫+景山；Day2: 颐和园+圆明园</td></tr><tr><td style="text-align:left;"><strong>3日游</strong></td><td style="text-align:left;">加上天坛+北海+王府井</td></tr><tr><td style="text-align:left;"><strong>5日游</strong></td><td style="text-align:left;">深度游览+长城+博物馆</td></tr><tr><td style="text-align:left;"><strong>7日游</strong></td><td style="text-align:left;">全面体验北京历史文化</td></tr></tbody></table><h2 id="北京概览" tabindex="-1">北京概览 <a class="header-anchor" href="#北京概览" aria-label="Permalink to &quot;北京概览&quot;">​</a></h2><h3 id="历史" tabindex="-1">历史 <a class="header-anchor" href="#历史" aria-label="Permalink to &quot;历史&quot;">​</a></h3><p>北京是中国首都，也是世界著名的历史文化名城。北京建城史可追溯至公元前1045年的西周燕国，作为都城的历史超过800年（金、元、明、清四朝）。</p><h3 id="地理" tabindex="-1">地理 <a class="header-anchor" href="#地理" aria-label="Permalink to &quot;地理&quot;">​</a></h3><p>北京位于华北平原北部，西靠太行山，北依燕山，东南面向华北平原。市中心位于北纬39°54′，东经116°23′。</p><h3 id="气候" tabindex="-1">气候 <a class="header-anchor" href="#气候" aria-label="Permalink to &quot;气候&quot;">​</a></h3><p>北京属于暖温带半湿润大陆性季风气候，四季分明：</p><table tabindex="0"><thead><tr><th style="text-align:left;">季节</th><th style="text-align:center;">时间</th><th style="text-align:center;">平均气温</th><th style="text-align:left;">特点</th></tr></thead><tbody><tr><td style="text-align:left;">春季</td><td style="text-align:center;">3-5月</td><td style="text-align:center;">3-21°C</td><td style="text-align:left;">干燥多风，偶有沙尘</td></tr><tr><td style="text-align:left;">夏季</td><td style="text-align:center;">6-8月</td><td style="text-align:center;">18-31°C</td><td style="text-align:left;">炎热多雨，闷热</td></tr><tr><td style="text-align:left;">秋季</td><td style="text-align:center;">9-11月</td><td style="text-align:center;">5-20°C</td><td style="text-align:left;">天高气爽，最佳季节</td></tr><tr><td style="text-align:left;">冬季</td><td style="text-align:center;">12-2月</td><td style="text-align:center;">-6-5°C</td><td style="text-align:left;">寒冷干燥，有雪</td></tr></tbody></table><h2 id="紧急联系" tabindex="-1">紧急联系 <a class="header-anchor" href="#紧急联系" aria-label="Permalink to &quot;紧急联系&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">服务</th><th style="text-align:left;">电话</th></tr></thead><tbody><tr><td style="text-align:left;">报警</td><td style="text-align:left;">110</td></tr><tr><td style="text-align:left;">急救</td><td style="text-align:left;">120</td></tr><tr><td style="text-align:left;">火警</td><td style="text-align:left;">119</td></tr><tr><td style="text-align:left;">旅游投诉</td><td style="text-align:left;">12345</td></tr><tr><td style="text-align:left;">北京旅游热线</td><td style="text-align:left;">010-12301</td></tr></tbody></table><hr><p>祝你在北京旅途愉快！</p>',21)])])}const y=e(i,[["render",r]]);export{x as __pageData,y as default};
